【结构分析报告（口播向）】
- 结构性原因：通过痛点共鸣和简单直接的CTA降低用户参与门槛，引发目标用户的关注和行动。

【结构拆解 JSON】
{
  "一、文案目标": [
    {
      "字段": "核心转化目标",
      "解析": "引导用户扣1获取框架"
    },
    {
      "字段": "目标用户所处认知阶段",
      "解析": "有一定内容创作经验，但效果不佳的创作者"
    },
    {
      "字段": "使用场景（冷启动 / 转化 / 复购 / 品牌）",
      "解析": "冷启动；吸引潜在学习者"
    }
  ],
  "二、宏观结构": [
    {
      "字段": "AIDA",
      "解析": "否；未明确包含注意-兴趣-欲望-行动四个阶段"
    },
    {
      "字段": "PAS",
      "解析": "否；未明确提出问题-放大-解决方案"
    },
    {
      "字段": "FAB",
      "解析": "否；未明确列出特征-优势-利益"
    },
    {
      "字段": "Before–After–Bridge",
      "解析": "否；未明确对比过去与未来状态"
    },
    {
      "字段": "4Ps",
      "解析": "否；未体现产品-价格-渠道-促销"
    },
    {
      "字段": "Hero's Journey",
      "解析": "否；未体现英雄旅程结构"
    }
  ],
  "三、心理驱动": [
    {
      "字段": "用户核心动机",
      "解析": "提升内容创作效率和效果"
    },
    {
      "字段": "使用的主要心理杠杆（最多2个）",
      "解析": "痛点共鸣；稀缺性（仅私发）"
    }
  ],
  "四、表达方式": [
    {
      "字段": "痛点是否具体化",
      "解析": "是；提到文案没人看、数据差"
